const body = $json.body && typeof $json.body === 'object' && !Array.isArray($json.body) ? $json.body : {};
const payload = Object.keys(body).length ? body : $json;
const transcriptSourceUrl = String(payload.transcript_source_url || payload.url || '').trim();

if (!transcriptSourceUrl) {
  throw new Error('transcript_source_url is required for 90_local_verify_transcript_mainline');
}

return {
  json: {
    ...payload,
    transcript_source_url: transcriptSourceUrl,
    source_name: String(payload.source_name || 'Local Transcript Verify').trim() || 'Local Transcript Verify',
    source_type: String(payload.source_type || 'transcript').trim() || 'transcript',
    media_type: String(payload.media_type || 'video').trim() || 'video',
    published_at: payload.published_at || new Date().toISOString(),
    obsidian_inbox_dir: String(payload.obsidian_inbox_dir || $env.OBSIDIAN_INBOX_DIR || '00_Inbox/AI_Information_Processor').trim() || '00_Inbox/AI_Information_Processor',
    original_request: {
      headers: $json.headers ?? {},
      params: $json.params ?? {},
      query: $json.query ?? {}
    }
  }
};

const metadata = $input.item.json && typeof $input.item.json === 'object' ? $input.item.json : {};

if (typeof metadata.error === 'string' && metadata.error.trim()) {
  return {
    json: {
      ok: false,
      stage: '04_video_transcript_ingest',
      error: metadata.error.trim(),
      error_metadata: $input.item.metadata ?? null,
      debug_input: $('Normalize Verify Request').item.json ?? {}
    }
  };
}

return {
  json: {
    ok: true,
    ...metadata
  }
};
